STAIR_SETS.push({ base: B.OASIS_STAIRS_PX, top: false, mat: 'planks', tex: 'oasis_planks', group: 'oasis', name: 'Oasis Stairs' });
STAIR_SETS.push({ base: B.OASIS_STAIRS_PX + 4, top: true, mat: 'planks', tex: 'oasis_planks', group: 'oasis', name: 'Oasis Stairs' });
STAIR_SETS.push({ base: B.GLASS_STAIRS_PX, top: false, mat: 'glass', tex: 'glass', group: 'glass', name: 'Glass Stairs' });
STAIR_SETS.push({ base: B.GLASS_STAIRS_PX + 4, top: true, mat: 'glass', tex: 'glass', group: 'glass', name: 'Glass Stairs' });
const STAIR_DIRS = [[1, 0], [-1, 0], [0, 1], [0, -1]];
function stairInfo(id) {
  for (const s of STAIR_SETS) {
    if (id >= s.base && id < s.base + 4) {
      return { dir: STAIR_DIRS[id - s.base], top: s.top, mat: s.mat, base: s.base, group: s.group, set: s };
    }
  }
  return null;
}
// legacy map kept for older code paths
const STAIR_DIR = {};
for (const s of STAIR_SETS) for (let d = 0; d < 4; d++) STAIR_DIR[s.base + d] = STAIR_DIRS[d];

// slab id -> exact material key (for mixed double-slab merging)
// The key is intentionally exact now. Old code reduced all planks to "plank"
// and all colored wool to "wool", which made some slab types impossible to
// stack together and made colored wool double slabs render as plain white.
const SLAB_MAT = {};
const SLAB_BOTTOM_OF = {};
const SLAB_TOP_OF = {};
const SLAB_OF = {};     // material key -> bottom slab item/block
const SLAB_TEX = {};    // material key -> atlas texture
const SLAB_NAME = {};   // material key -> readable name

function defSlabKind(key, bottomId, topId, tex, name) {
  SLAB_MAT[bottomId] = key;
  SLAB_MAT[topId] = key;
  SLAB_BOTTOM_OF[topId] = bottomId;
  SLAB_TOP_OF[bottomId] = topId;
  SLAB_OF[key] = bottomId;
  SLAB_TEX[key] = tex;
  SLAB_NAME[key] = name;
}

defSlabKind('oak', B.PLANK_SLAB_B, B.PLANK_SLAB_T, 'planks', 'Oak Slab');
defSlabKind('cobble', B.COBBLE_SLAB_B, B.COBBLE_SLAB_T, 'cobble', 'Cobblestone Slab');
defSlabKind('stone', B.STONE_SLAB_B, B.STONE_SLAB_T, 'stone', 'Stone Slab');
defSlabKind('wool_white', B.WOOL_SLAB_B, B.WOOL_SLAB_T, 'wool', 'White Wool Slab');
for (let ci = 0; ci < WOOL_STAIR_COLORS.length; ci++) {
  const col = WOOL_STAIR_COLORS[ci];
  const nm = col[0].toUpperCase() + col.slice(1) + ' Wool Slab';
  defSlabKind('wool_' + col, B.WOOL_SLAB_C0 + ci * 2, B.WOOL_SLAB_C0 + ci * 2 + 1, 'wool_' + col, nm);
}
defSlabKind('birch', B.BIRCH_SLAB_B, B.BIRCH_SLAB_T, 'birch_planks', 'Birch Slab');
defSlabKind('spruce', B.SPRUCE_SLAB_B, B.SPRUCE_SLAB_T, 'spruce_planks', 'Spruce Slab');
defSlabKind('oasis', B.OASIS_SLAB_B, B.OASIS_SLAB_T, 'oasis_planks', 'Oasis Slab');
defSlabKind('glass', B.GLASS_SLAB_B, B.GLASS_SLAB_T, 'glass', 'Glass Slab');

// double slab id from (bottom exact slab key, top exact slab key)
// Keep the original IDs for old saves/legacy combinations, then assign a
// dynamic ID to every other slab pair. This lets any slab stack with any slab.
const DSLAB_LEGACY_ID = {
  'oak|oak': B.DSLAB_PLANK,
  'cobble|cobble': B.DSLAB_COBBLE,
  'stone|stone': B.DSLAB_STONE,
  'wool_white|wool_white': B.DSLAB_WOOL,
  'oak|cobble': B.DSLAB_PC, 'cobble|oak': B.DSLAB_CP,
  'oak|stone': B.DSLAB_PS, 'stone|oak': B.DSLAB_SP,
  'cobble|stone': B.DSLAB_CS, 'stone|cobble': B.DSLAB_SC,
};
const DSLAB_ID = {};
const DSLAB_MATS = {}; // id -> [bottomKey, topKey]
let __nextDSlabId = B.DSLAB_MIX_C0;
const __slabKeys = Object.keys(SLAB_OF);
for (const botKey of __slabKeys) {
  for (const topKey of __slabKeys) {
    const key = botKey + '|' + topKey;
    const id = DSLAB_LEGACY_ID[key] || (__nextDSlabId++);
    DSLAB_ID[key] = id;
    DSLAB_MATS[id] = [botKey, topKey];
  }
}

// Vertical slab support. Players still hold the normal slab item; pressing X toggles
// placement into these hidden vertical variants. Two slab pieces in one block are
// encoded as slabCombo blocks so mixed wool colors/materials keep their identity.
const SLAB_ORIENT_ORDER = { bottom: 0, top: 1, nx: 2, px: 3, nz: 4, pz: 5 };
const VSLAB_DIRS = ['nx', 'px', 'nz', 'pz'];
const VSLAB_INFO = {};       // id -> { mat, orient }
const VSLAB_ID = {};         // mat|orient -> hidden vertical slab id
const SLAB_PARTS_BY_KEY = {}; // mat:orient -> { id, mat, orient }

function __slabHard(mat) { return mat === 'cobble' ? 5 : mat === 'stone' ? 4.5 : mat === 'glass' ? 0.5 : mat.startsWith('wool') ? 0.9 : 2.2; }
function __slabTool(mat) { return (mat === 'cobble' || mat === 'stone') ? 'pickaxe' : mat === 'glass' || mat.startsWith('wool') ? null : 'axe'; }
function __slabFlammable(mat) { return !(mat === 'cobble' || mat === 'stone' || mat === 'glass'); }
function __registerSlabPart(id, mat, orient) {
  SLAB_PARTS_BY_KEY[mat + ':' + orient] = { id, mat, orient };
}
for (const key of __slabKeys) {
  __registerSlabPart(SLAB_OF[key], key, 'bottom');
  __registerSlabPart(SLAB_TOP_OF[SLAB_OF[key]], key, 'top');
}
let __nextVSlabId = B.VSLAB_C0;
for (const mat of __slabKeys) {
  for (const orient of VSLAB_DIRS) {
    const id = __nextVSlabId++;
    VSLAB_ID[mat + '|' + orient] = id;
    VSLAB_INFO[id] = { mat, orient };
    __registerSlabPart(id, mat, orient);
  }
}

function slabPartInfo(id) {
  if (isSlab(id)) {
    const mat = SLAB_MAT[id];
    if (!mat) return null;
    const def = Reg[id];
    return { id, mat, orient: def && def.shape === 'slabT' ? 'top' : 'bottom' };
  }
  if (isVSlab(id)) return { id, mat: VSLAB_INFO[id].mat, orient: VSLAB_INFO[id].orient };
  return null;
}
function isLowerHorizontalSlab(id) {
  const info = slabPartInfo(id);
  const def = Reg[id];
  return !!info && info.orient === 'bottom' && def && def.shape === 'slabB';
}
function slabPartKeyFromInfo(info) { return info.mat + ':' + info.orient; }
function slabPartKey(id) { const info = slabPartInfo(id); return info ? slabPartKeyFromInfo(info) : null; }
function slabPartDropId(part) { return part ? SLAB_OF[part.mat] : null; }
function slabPartBox(part) {
  if (!part) return null;
  switch (part.orient) {
    case 'bottom': return [0, 0, 0, 1, 0.5, 1];
    case 'top': return [0, 0.5, 0, 1, 1, 1];
    case 'nx': return [0, 0, 0, 0.5, 1, 1];
    case 'px': return [0.5, 0, 0, 1, 1, 1];
    case 'nz': return [0, 0, 0, 1, 1, 0.5];
    case 'pz': return [0, 0, 0.5, 1, 1, 1];
    default: return [0, 0, 0, 1, 1, 1];
  }
}
function slabBoxForId(id) { return slabPartBox(slabPartInfo(id)); }
function slabComboBoxes(id) {
  const parts = SLAB_COMBO_PIECES[id];
  if (!parts) return null;
  return parts.map(p => slabPartBox(p));
}
function __slabComboKey(a, b) {
  const ka = slabPartKeyFromInfo(a), kb = slabPartKeyFromInfo(b);
  const oa = SLAB_ORIENT_ORDER[a.orient], ob = SLAB_ORIENT_ORDER[b.orient];
  if (oa < ob) return ka + '|' + kb;
  if (ob < oa) return kb + '|' + ka;
  return ka < kb ? ka + '|' + kb : kb + '|' + ka;
}
function slabOrientAxis(orient) {
  if (orient === 'bottom' || orient === 'top') return 'y';
  if (orient === 'nx' || orient === 'px') return 'x';
  if (orient === 'nz' || orient === 'pz') return 'z';
  return null;
}
function oppositeSlabOrient(orient) {
  return { bottom: 'top', top: 'bottom', nx: 'px', px: 'nx', nz: 'pz', pz: 'nz' }[orient] || null;
}
function slabPartsCanMerge(a, b) {
  if (!a || !b) return false;
  if (a.orient === b.orient) return false;
  const axisA = slabOrientAxis(a.orient);
  const axisB = slabOrientAxis(b.orient);
  // Two pieces may share a block only when they split the block on the same axis.
  // This prevents bad L/corner pairs like nx+nz that overlap and z-fight.
  return axisA && axisA === axisB && oppositeSlabOrient(a.orient) === b.orient;
}
function slabComboIdFor(aId, bId) {
  const a = slabPartInfo(aId), b = slabPartInfo(bId);
  if (!slabPartsCanMerge(a, b)) return null;
  // Keep the old/full horizontal double slab IDs for top+bottom slabs.
  if ((a.orient === 'bottom' && b.orient === 'top') || (a.orient === 'top' && b.orient === 'bottom')) {
    const bot = a.orient === 'bottom' ? a : b;
    const top = a.orient === 'top' ? a : b;
    return DSLAB_ID[bot.mat + '|' + top.mat] || null;
  }
  return SLAB_COMBO_ID[__slabComboKey(a, b)] || null;
}
function slabComboDropIds(id) {
  if (DSLAB_MATS[id]) return DSLAB_MATS[id].map(m => SLAB_OF[m]);
  const parts = SLAB_COMBO_PIECES[id];
  return parts ? parts.map(p => slabPartDropId(p)).filter(Boolean) : [];
}

const SLAB_COMBO_ID = {};
const SLAB_COMBO_PIECES = {}; // id -> [{mat, orient}, {mat, orient}]
let __nextSlabComboId = B.SLAB_COMBO_C0;
const __allSlabParts = Object.values(SLAB_PARTS_BY_KEY);
for (let i = 0; i < __allSlabParts.length; i++) {
  for (let j = i + 1; j < __allSlabParts.length; j++) {
    const a = __allSlabParts[i], b = __allSlabParts[j];
    if (a.orient === b.orient) continue;
    if ((a.orient === 'bottom' && b.orient === 'top') || (a.orient === 'top' && b.orient === 'bottom')) continue; // DSLAB already covers it
    const ck = __slabComboKey(a, b);
    if (!SLAB_COMBO_ID[ck]) {
      const id = __nextSlabComboId++;
      SLAB_COMBO_ID[ck] = id;
      SLAB_COMBO_PIECES[id] = [a, b];
    }
  }
}

