// Registry
// ---------------------------------------------------------------
const Reg = {};
function defBlock(id, name, o) {
  Reg[id] = Object.assign({
    name, block: true, stack: 64, hard: 1, tool: null, reqTier: -1,
    drop: undefined, solid: true, opaque: true, cutout: false,
    replaceable: false, interact: null, xp: 0, shape: 'cube',
    lightLevel: 0, flammable: false, gravity: false, weak: false,
    tex: { all: 'stone' },
  }, o);
}
function defItem(id, name, o) {
  Reg[id] = Object.assign({ name, block: false, stack: 64 }, o);
}

