function defDoorSet(xb, name, botTex, topTex, dropId) {
  // xb, xb+1=xt, +2=zb, +3=zt for closed; open set passed separately
  defBlock(xb, name, { hard: 2.5, tool: 'axe', flammable: true, opaque: false, cutout: true, interact: 'door', drop: { id: dropId }, shape: 'door', tex: { all: botTex } });
  defBlock(xb + 1, name, { hard: 2.5, tool: 'axe', flammable: true, opaque: false, cutout: true, interact: 'door', drop: null, shape: 'door', tex: { all: topTex } });
  defBlock(xb + 2, name, { hard: 2.5, tool: 'axe', flammable: true, opaque: false, cutout: true, interact: 'door', drop: { id: dropId }, shape: 'door', tex: { all: botTex } });
  defBlock(xb + 3, name, { hard: 2.5, tool: 'axe', flammable: true, opaque: false, cutout: true, interact: 'door', drop: null, shape: 'door', tex: { all: topTex } });
}
